// ════════════════════════════════════════════════════════
// EXTRAER FILTROS DEL QUERY ESTRUCTURADO
// ════════════════════════════════════════════════════════

const query = $json.original_query || '';
const searchQuery = $json.search_query || '';
const queryType = $json.query_type || '';
const queryId = $json.query_id || '';

// Parsear filtros del query estructurado
const filters = {};
if (query.includes(';')) {
  query.split(';').forEach(pair => {
    const [key, value] = pair.split(':');
    if (key && value) filters[key.trim()] = value.trim();
  });
}

// Construir objeto de filtros limpios
const cleanFilters = {
  ambientes: filters.ambientes ? parseInt(filters.ambientes) : null,
  precio_max: (filters.precio_max && filters.precio_max !== '9999999') ? parseInt(filters.precio_max) : null,
  precio_min: (filters.precio_min && filters.precio_min !== '0') ? parseInt(filters.precio_min) : null,
  zona: filters.zona || null,
  operacion: filters.operacion || null,
  tipo: filters.tipo || null,
  moneda: filters.moneda || null
};

// Log para debug
console.log('═══════════════════════════════════════');
console.log('📋 FILTROS EXTRAÍDOS:');
console.log(JSON.stringify(cleanFilters, null, 2));
console.log('═══════════════════════════════════════');

return [{
  json: {
    query_id: queryId,
    search_query: searchQuery,
    query_type: queryType,
    filters: cleanFilters,
    // Filtros individuales para fácil acceso en expresiones
    filter_ambientes: cleanFilters.ambientes,
    filter_precio_max: cleanFilters.precio_max,
    filter_zona: cleanFilters.zona,
    filter_operacion: cleanFilters.operacion,
    filter_tipo: cleanFilters.tipo
  }
}];

// ════════════════════════════════════════════════════════
// DETECTAR TIPO DE QUERY Y PREPARAR BÚSQUEDA
// ════════════════════════════════════════════════════════

const query = $json.query || '';
const queryId = $json.query_id || '';

console.log('═══════════════════════════════════════');
console.log('📝 QUERY RECEIVED:', query);
console.log('📝 QUERY ID:', queryId);

// ─── DETECTAR TIPO DE QUERY ───
const isStructuredQuery = query.includes(':') && query.includes(';');

let searchQuery = '';
let queryType = '';

if (isStructuredQuery) {
  // ════════════════════════════════════════════════════════
  // TIPO A: QUERY ESTRUCTURADO (actual)
  // ════════════════════════════════════════════════════════
  queryType = 'structured';

  // Parsear query estructurado
  const params = {};
  query.split(';').forEach(pair => {
    const [key, value] = pair.split(':');
    if (key && value) params[key] = value;
  });

  console.log('Query Type: STRUCTURED');
  console.log('Parsed params:', JSON.stringify(params, null, 2));

  // Construir query de texto para búsqueda vectorial
  const parts = [];

  if (params.tipo) parts.push(params.tipo);
  if (params.ambientes) parts.push(`${params.ambientes} ambientes`);
  if (params.zona) parts.push(`en ${params.zona}`);
  if (params.operacion) parts.push(params.operacion);
  if (params.moneda && params.precio_max) {
    if (params.precio_max !== '9999999') {
      parts.push(`hasta ${params.moneda} ${params.precio_max}`);
    }
  }
  if (params.caracteristicas) parts.push(params.caracteristicas);

  searchQuery = parts.join(' ');

} else {
  // ════════════════════════════════════════════════════════
  // TIPO B: QUERY DE TEXTO LIBRE (nuevo)
  // ════════════════════════════════════════════════════════
  queryType = 'freetext';
  searchQuery = query;

  console.log('Query Type: FREE TEXT');
}

console.log('Search Query:', searchQuery);
console.log('═══════════════════════════════════════');

return [{
  json: {
    query_id: queryId,
    original_query: query,
    search_query: searchQuery,
    query_type: queryType
  }
}];

// ════════════════════════════════════════════════════════
// FILTRAR RESULTADOS (VERSIÓN MEJORADA - MÁS FLEXIBLE)
// ════════════════════════════════════════════════════════
// ✅ MEJORAS:
// - Filtro de ambientes con rango ±1
// - Filtro de operación con búsqueda parcial (includes)
// - Mejor manejo de propiedades sin precio
// ════════════════════════════════════════════════════════

const results = $input.all();

// Obtener filtros del nodo anterior
const prevData = $('Code in JavaScript1').first().json;
const filters = prevData.filters;

console.log('═══════════════════════════════════════');
console.log('📋 Filtros a aplicar:', JSON.stringify(filters));
console.log('📊 Resultados de Supabase:', results.length);

const filtered = results.filter(item => {
  const meta = item.json.document?.metadata?.metadata || {};

  // ✅ FILTRO POR AMBIENTES ESTRICTO
  if (filters.ambientes !== null) {
    const propAmbientes = meta.ambientes || 0;
    const filterAmbientes = filters.ambientes;

    if (propAmbientes !== filterAmbientes) {
      console.log(`❌ Excluido: ${meta.tokko_id} - ambientes ${propAmbientes} !== ${filterAmbientes}`);
      return false;
    }
  }

  // Filtro por precio mínimo (solo si la propiedad tiene precio)
  if (filters.precio_min !== null && meta.precio !== null && meta.precio < filters.precio_min) {
    console.log(`❌ Excluido: ${meta.tokko_id} - precio ${meta.precio} < ${filters.precio_min}`);
    return false;
  }

  // Filtro por precio máximo (solo si la propiedad tiene precio)
  if (filters.precio_max !== null && meta.precio !== null && meta.precio > filters.precio_max) {
    console.log(`❌ Excluido: ${meta.tokko_id} - precio ${meta.precio} > ${filters.precio_max}`);
    return false;
  }

  // Filtro por zona (búsqueda flexible - includes)
  if (filters.zona !== null) {
    const propZona = (meta.zona || meta.barrio || meta.distrito || '').toLowerCase();
    const filterZona = filters.zona.toLowerCase();

    if (!propZona.includes(filterZona)) {
      console.log(`❌ Excluido: ${meta.tokko_id} - zona "${propZona}" no incluye "${filterZona}"`);
      return false;
    }
  }

  // ✅ MEJORA: Filtro por operación CON BÚSQUEDA PARCIAL (includes)
  if (filters.operacion !== null) {
    const propOperacion = (meta.operacion || '').toLowerCase();
    const filterOperacion = filters.operacion.toLowerCase();

    // Usar includes en lugar de === para soportar "alquiler, alquiler temporario"
    if (!propOperacion.includes(filterOperacion)) {
      console.log(`❌ Excluido: ${meta.tokko_id} - operacion "${propOperacion}" no incluye "${filterOperacion}"`);
      return false;
    }
  }

  // Filtro por tipo de propiedad
  if (filters.tipo !== null) {
    const propTipo = (meta.tipo_propiedad || meta.tipo_inmueble || '').toLowerCase();
    const filterTipo = filters.tipo.toLowerCase();

    if (!propTipo.includes(filterTipo)) {
      console.log(`❌ Excluido: ${meta.tokko_id} - tipo "${propTipo}" no incluye "${filterTipo}"`);
      return false;
    }
  }

  console.log(`✅ Incluido: ${meta.tokko_id} - ${meta.titulo}`);
  return true;
});

console.log(`📊 Resultado: ${results.length} → ${filtered.length}`);
console.log('═══════════════════════════════════════');

// Score mínimo (más bajo para permitir más resultados)
const MIN_SCORE = 0.4;  
const highQualityResults = filtered.filter(item => {
  const score = item.json.score || 0;
  if (score < MIN_SCORE) {
    console.log(`⚠️ Baja relevancia: ${item.json.document?.metadata?.metadata?.tokko_id} - score ${score}`);
    return false;
  }
  return true;
});

// Si no hay resultados de alta calidad, incluir todos los filtrados
const finalResults = highQualityResults.length > 0 ? highQualityResults : filtered;

const propiedades = finalResults.map(item => {
  const meta = item.json.document?.metadata?.metadata || {};
  return {
    tokko_id: meta.tokko_id,
    titulo: meta.titulo,
    direccion: meta.direccion,
    barrio: meta.barrio || meta.zona,
    precio: meta.precio,
    moneda: meta.moneda,
    ambientes: meta.ambientes,
    dormitorios: meta.dormitorios,
    banos: meta.banos,
    cocheras: meta.cocheras,
    imagen: meta.imagen,
    link_web: meta.link_web,
    asesor: meta.asesor,
    score: item.json.score
  };
});

return [{
  json: {
    success: propiedades.length > 0,
    total: propiedades.length,
    propiedades: propiedades,
    debug: {
      results_before_filter: results.length,
      results_after_filter: filtered.length,
      results_after_score_filter: finalResults.length,
      filters_applied: filters,
      min_score: MIN_SCORE
    }
  }
}];
